CREATE SCHEMA IF NOT EXISTS ecommerce;

CREATE TABLE ecommerce.users (
  user_id     BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  email       VARCHAR(255) NOT NULL UNIQUE,
  password_hash VARCHAR(255) NOT NULL,
  first_name  VARCHAR(100),
  last_name   VARCHAR(100),
  phone       VARCHAR(30),
  is_verified BOOLEAN NOT NULL DEFAULT FALSE,
  is_active   BOOLEAN NOT NULL DEFAULT TRUE,
  created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at  TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE ecommerce.addresses (
  address_id   BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  user_id      BIGINT NOT NULL REFERENCES ecommerce.users(user_id) ON DELETE CASCADE,
  label        VARCHAR(50) DEFAULT 'home',
  full_name    VARCHAR(200),
  line1        VARCHAR(255) NOT NULL,
  line2        VARCHAR(255),
  city         VARCHAR(100) NOT NULL,
  state        VARCHAR(100),
  postal_code  VARCHAR(20) NOT NULL,
  country      VARCHAR(100) NOT NULL DEFAULT 'US',
  is_default   BOOLEAN NOT NULL DEFAULT FALSE,
  created_at   TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at   TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE ecommerce.categories (
  category_id   BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  parent_id     BIGINT REFERENCES ecommerce.categories(category_id) ON DELETE SET NULL,
  name          VARCHAR(150) NOT NULL,
  slug          VARCHAR(150) NOT NULL UNIQUE,
  description   TEXT,
  is_active     BOOLEAN NOT NULL DEFAULT TRUE,
  created_at    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at    TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE ecommerce.products (
  product_id    BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  category_id   BIGINT REFERENCES ecommerce.categories(category_id) ON DELETE SET NULL,
  name          VARCHAR(255) NOT NULL,
  slug          VARCHAR(255) NOT NULL UNIQUE,
  description   TEXT,
  sku           VARCHAR(100) UNIQUE,
  price         NUMERIC(12,2) NOT NULL CHECK (price >= 0),
  stock_qty     INT NOT NULL DEFAULT 0 CHECK (stock_qty >= 0),
  is_active     BOOLEAN NOT NULL DEFAULT TRUE,
  created_at    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at    TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE ecommerce.product_images (
  image_id     BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  product_id   BIGINT NOT NULL REFERENCES ecommerce.products(product_id) ON DELETE CASCADE,
  url          TEXT NOT NULL,
  alt_text     VARCHAR(255),
  is_primary   BOOLEAN NOT NULL DEFAULT FALSE,
  sort_order   INT NOT NULL DEFAULT 0,
  created_at   TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE ecommerce.carts (
  cart_id      BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  user_id      BIGINT REFERENCES ecommerce.users(user_id) ON DELETE CASCADE,
  session_id   VARCHAR(255),
  created_at   TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at   TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  CONSTRAINT chk_cart_owner CHECK (user_id IS NOT NULL OR session_id IS NOT NULL)
);

CREATE TABLE ecommerce.cart_items (
  cart_item_id BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  cart_id      BIGINT NOT NULL REFERENCES ecommerce.carts(cart_id) ON DELETE CASCADE,
  product_id   BIGINT NOT NULL REFERENCES ecommerce.products(product_id) ON DELETE CASCADE,
  quantity     INT NOT NULL DEFAULT 1 CHECK (quantity > 0),
  added_at     TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  UNIQUE (cart_id, product_id)
);

CREATE TABLE ecommerce.orders (
  order_id         BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  user_id          BIGINT NOT NULL REFERENCES ecommerce.users(user_id) ON DELETE RESTRICT,
  shipping_address_id BIGINT REFERENCES ecommerce.addresses(address_id) ON DELETE SET NULL,
  status           VARCHAR(50) NOT NULL DEFAULT 'pending'
                     CHECK (status IN ('pending','confirmed','processing','shipped','delivered','cancelled','refunded')),
  subtotal         NUMERIC(12,2) NOT NULL DEFAULT 0,
  shipping_cost    NUMERIC(12,2) NOT NULL DEFAULT 0,
  tax              NUMERIC(12,2) NOT NULL DEFAULT 0,
  total            NUMERIC(12,2) NOT NULL DEFAULT 0,
  notes            TEXT,
  created_at       TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at       TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE ecommerce.order_items (
  order_item_id  BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  order_id       BIGINT NOT NULL REFERENCES ecommerce.orders(order_id) ON DELETE CASCADE,
  product_id     BIGINT REFERENCES ecommerce.products(product_id) ON DELETE SET NULL,
  product_name   VARCHAR(255) NOT NULL,
  unit_price     NUMERIC(12,2) NOT NULL,
  quantity       INT NOT NULL CHECK (quantity > 0),
  line_total     NUMERIC(12,2) GENERATED ALWAYS AS (unit_price * quantity) STORED
);

CREATE TABLE ecommerce.payments (
  payment_id      BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  order_id        BIGINT NOT NULL REFERENCES ecommerce.orders(order_id) ON DELETE RESTRICT,
  method          VARCHAR(50) NOT NULL CHECK (method IN ('credit_card','debit_card','paypal','stripe','bank_transfer','wallet')),
  status          VARCHAR(50) NOT NULL DEFAULT 'pending' CHECK (status IN ('pending','completed','failed','refunded')),
  amount          NUMERIC(12,2) NOT NULL,
  transaction_id  VARCHAR(255) UNIQUE,
  paid_at         TIMESTAMPTZ,
  created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at      TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE ecommerce.reviews (
  review_id    BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  product_id   BIGINT NOT NULL REFERENCES ecommerce.products(product_id) ON DELETE CASCADE,
  user_id      BIGINT NOT NULL REFERENCES ecommerce.users(user_id) ON DELETE CASCADE,
  rating       SMALLINT NOT NULL CHECK (rating BETWEEN 1 AND 5),
  title        VARCHAR(255),
  body         TEXT,
  is_approved  BOOLEAN NOT NULL DEFAULT FALSE,
  created_at   TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at   TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  UNIQUE (product_id, user_id)
);

