-- View: product summary with avg rating
CREATE OR REPLACE VIEW ecommerce.v_product_summary AS
SELECT
  p.product_id,
  p.name,
  p.slug,
  p.price,
  p.stock_qty,
  p.is_active,
  c.name          AS category_name,
  ROUND(AVG(r.rating)::NUMERIC, 2) AS avg_rating,
  COUNT(r.review_id)               AS review_count
FROM ecommerce.products p
LEFT JOIN ecommerce.categories c ON c.category_id = p.category_id
LEFT JOIN ecommerce.reviews    r ON r.product_id  = p.product_id AND r.is_approved
GROUP BY p.product_id, p.name, p.slug, p.price, p.stock_qty, p.is_active, c.name;

-- View: order summary with user info and payment status
CREATE OR REPLACE VIEW ecommerce.v_order_summary AS
SELECT
  o.order_id,
  o.status        AS order_status,
  o.total,
  o.created_at    AS ordered_at,
  u.user_id,
  u.email,
  u.first_name,
  u.last_name,
  COUNT(oi.order_item_id) AS item_count,
  pay.status      AS payment_status,
  pay.method      AS payment_method
FROM ecommerce.orders o
JOIN ecommerce.users       u   ON u.user_id   = o.user_id
LEFT JOIN ecommerce.order_items oi  ON oi.order_id  = o.order_id
LEFT JOIN ecommerce.payments    pay ON pay.order_id  = o.order_id
GROUP BY o.order_id, o.status, o.total, o.created_at,
         u.user_id, u.email, u.first_name, u.last_name,
         pay.status, pay.method;

-- View: cart details with product info and line totals
CREATE OR REPLACE VIEW ecommerce.v_cart_details AS
SELECT
  c.cart_id,
  c.user_id,
  c.session_id,
  ci.cart_item_id,
  p.product_id,
  p.name          AS product_name,
  p.price         AS unit_price,
  ci.quantity,
  (p.price * ci.quantity) AS line_total
FROM ecommerce.carts      c
JOIN ecommerce.cart_items ci ON ci.cart_id    = c.cart_id
JOIN ecommerce.products   p  ON p.product_id  = ci.product_id;
